#!/usr/bin/env bun
// PreToolUse hook: block Agent prompts that use bare git commands for session work,
// and warn when session-work prompts were not generated by session.generate_prompt.
//
// Two checks:
// 1. DENY: bare git commands (git add, git commit, git push) in prompts — always wrong
// 2. WARN: session_commit without watermark — hand-crafted but using correct tools

import { readInput, writeOutput } from "./types";
import type { ToolHookInput } from "./types";

const input = await readInput<ToolHookInput>();
const prompt = (input.tool_input.prompt as string) ?? "";

// Check for bare git commands — these are NEVER correct in session work
const bareGitPatterns = [/\bgit\s+add\b/, /\bgit\s+commit\b/, /\bgit\s+push\b/, /\bgit\s+-C\b/];
const hasBareGit = bareGitPatterns.some((pattern) => pattern.test(prompt));

if (hasBareGit) {
  writeOutput({
    hookSpecificOutput: {
      hookEventName: "PreToolUse",
      permissionDecision: "deny",
      permissionDecisionReason:
        "Agent prompt contains bare git commands (git add/commit/push). " +
        "Use MCP tools instead: session_commit, session_pr_create. " +
        "Regenerate the prompt with session.generate_prompt.",
    },
  });
  process.exit(0);
}

// Check for session work without watermark (hand-crafted but using correct tools)
const isSessionWork = prompt.includes("session_commit");
const hasWatermark = prompt.includes("minsky:prompt:v1");

if (isSessionWork && !hasWatermark) {
  console.log(
    "⚠️ This Agent prompt dispatches session work but was not generated by session.generate_prompt."
  );
  console.log(
    "Use mcp__minsky__session_generate_prompt to generate a prompt with correct metadata."
  );
  console.log("If the tool is unavailable, restart the MCP server with /mcp.");
}

process.exit(0);
